axiosRetry(AppsApi, {
  retries: 3,
  retryDelay: axiosRetry.exponentialDelay,
  retryCondition: (err) => {
    const method = err.config?.method?.toUpperCase();
    return (
      (method === "PUT" || method === "PATCH") &&
      (err.response?.status === undefined || err.response.status >= 500)
    );
  },
});

const localSkanOptOut = computed({
  get: () => props.skanOptOut,
  set: (value) => emit("update:skanOptOut", value),
});

const appleAppID = Number(appData.app_store_id);
const hasValidAppleAppID = Number.isFinite(appleAppID) && appleAppID > 0;
const shouldAutoEnable =
  appData.platform === "ios" &&
  appData.integration_type !== "s2s" &&
  appData.skan_opt_out !== true &&
  validStatuses.includes(appData.app_store_validation_status || "") &&
  hasValidAppleAppID;

if (!shouldAutoEnable) return;

try {
  const existing = await SkadApi.get(endpoints.skad.get(appId), {
    headers: { "Authentication-Key": organizationStore.accountApiKey },
  });
  if (existing.data?.data?.model_id && existing.data.data.model_id !== "install_only") {
    return;
  }
} catch {
  // 404 = no model = expected for new apps; proceed
}

const id = props.bundleId;
if (props.platform.toLowerCase() !== "ios") return;
if (!/^[0-9]{1,15}$/.test(id)) return;
if (id === lastValidatedId.value) return;
lastValidatedId.value = id;

const onBundleIdBlur = async () => {
  const id = props.bundleId;
  if (props.platform.toLowerCase() !== "ios") return;
  if (!/^[0-9]{1,15}$/.test(id)) return;
  if (id === lastValidatedId.value) return;

} catch (patchErr) {
  console.warn("Failed to set skan_auto_enable_failed flag", patchErr);
}
notificationsStore.addNotification({
  type: "warning",
  text: "messages.notifications.skan_manual_config_needed",
});

const shouldAutoEnable =
  appData.platform === "ios" &&
  appData.integration_type !== "s2s" &&
  appData.skan_opt_out !== true &&
  validStatuses.includes(appData.app_store_validation_status || "") &&
  hasValidAppleAppID;

// T304: Auto-enable SKAN tracking for eligible iOS SDK apps
await autoEnableSkan(resp.data.app_id, payload.app_data);

return { success: true, appId: resp.data.app_id };

if (existing.data?.data?.model_id && existing.data.data.model_id !== "install_only") {
  return;
}

axiosRetry(AppsApi, {
  retries: 3,
  retryDelay: axiosRetry.exponentialDelay,
  retryCondition: (err) => {
    const method = err.config?.method?.toUpperCase();
    return (
      (method === "PUT" || method === "PATCH") &&
      (err.response?.status === undefined || err.response.status >= 500)
    );
  },
});

} catch (patchErr) {
  console.warn("Failed to set skan_auto_enable_failed flag", patchErr);
}

