      if (integrationType === "s2s") {
        return "s2s";
      }
      // For all other cases (empty string or platform SDK), return "sdk"
      return "sdk";
    },
    set: (value: string) => {
      // If selecting s2s, set integration_type directly
      if (value === "s2s") {
        appsStore.currentAppForm.app_data.integration_type = "s2s";
      } else if (value === "sdk") {
        // Clear to empty string when SDK is selected without a platform
        appsStore.currentAppForm.app_data.integration_type = "";
      }
    },
  });

  // SDK platform selection: the actual integration_type value (e.g., "adobe-air")
  const selectedSdkPlatform = computed({
    get: () => {
      const integrationType = appsStore.currentAppForm.app_data.integration_type || "";
      // If integration_type is not s2s or sdk, it's the SDK platform
      if (integrationType && integrationType !== "s2s" && integrationType !== "sdk") {
        return integrationType;
      }
