    return (filterBy: FilteredRevenueEventKey[]): string[] => {
      if (!filterBy?.length) return eventMetaDataFilterKeys.value;
      const filterByKeys = [];

      for (let i = 0; i < filterBy.length; i++) {
        filterByKeys.push(filterBy[i].key);
      }

      function filterKeys(keys: string[]): string[] {
        if (keys.length < 1) return [];
        return filterByKeys.includes(keys[0]) ? [].concat(filterKeys(keys.slice(1))) : [keys[0]].concat(filterKeys(keys.slice(1)));
      }

      return filterKeys(eventMetaDataFilterKeys.value);
